$(document).ready(function() {
    var baseUrl = window.location.origin;
    let get_cusomer_url = baseUrl+'/search_customer';
    let search_on_code = baseUrl+'/search_on_code';
    let search_on_pooja = baseUrl+'/search_on_pooja';
    let submit_pooja_values = baseUrl+'/submit_pooja_values';
    $.ajaxSetup({
        headers: {
            'X-CSRF-TOKEN': $('meta[name="csrf-token"]').attr('content')
        }
    });    
 
    var customer_name_input_value = '';
    var pooja_code ='';
    var pooja_amount = ''
    var pooja_name ='';
    var pooja_qty = '';
    var customerId = '';
    var poojaDetails = [];
    $('.customer_name').keyup(function(){
        customer_name_input_value = $(this).val();
        $.ajax({
            url:get_cusomer_url,
            data:{
                    search_value:customer_name_input_value
                  },
            dataType: 'json',
            type:'GET',
            success: function(response) {
                var results = response; // Assuming the JSON response has a 'data' key
                var dropdownMenu = $('.dropdown-menu');
                dropdownMenu.empty(); // Clear previous results
                results.forEach(function(result) {
                    var mob_no = ' - ( '+result.mobile_no+' )';
                    dropdownMenu.append(`<a class="dropdown-item" href="#" data-customer-id="${result.id}" data-customer-name="${result.customer_name}">${result.customer_name + mob_no}</a>`);
                });


                // Show the dropdown menu
                dropdownMenu.show();
            },
            error: function(xhr, status, error) {
                console.error(error);
            }
        });
       
    });
  // Dropdown item click event for customer search
  $('.dropdown-menu').on('click', '.dropdown-item', function(e) {
        e.preventDefault();
         customerId = $(this).data('customer-id');
        var customerName = $(this).data('customer-name');
       
        $('.customer_name').val(customerName); // Update dropdown button text
        $('.dropdown-menu').hide(); // Hide dropdown menu


        // Use customerId or customerName as needed
       // console.log('Selected Customer ID:', customerId);
        //console.log('Selected Customer Name:', customerName);
    });


    $(document).on('keyup', '.pooja_name', function() {
        var pooja_name_search = $(this).val();
        var row = $(this).closest('.row'); // Find the closest parent row
        $.ajax({
            url:search_on_pooja,
            data:{
                    search_value:pooja_name_search
                  },
            dataType: 'json',
            type:'GET',
            success: function(response) {
                var results = response; // Assuming the JSON response has a 'data' key


                var dropdownMenu = row.find('.dropdown-menu-pooja');
                dropdownMenu.empty(); // Clear previous results
                results.forEach(function(result) {
                    //var mob_no = ' - ( '+result.mobile_no+' )';
                    dropdownMenu.append(`<a class="dropdown-item pooja-dropdown" href="#"  data-pooja-id="${result.id}" data-pooja-name="${result.pooja_name}" data-pooja-code="${result.code}" data-pooja-amount="${result.amount}">${result.pooja_name}</a>`);
                });


                // Show the dropdown menu
                dropdownMenu.show();
            },
            error: function(xhr, status, error) {
                console.error(error);
            }
        });


    });


    // Dropdown item click event for pooja search
     $(document).on('click', '.pooja-dropdown', function() {
        var poojaId = $(this).data('pooja-id');
        var poojaName = $(this).data('pooja-name');
        var pooja_code = $(this).data('pooja-code');
        var pooja_amount = $(this).data('pooja-amount');
       
        var row = $(this).closest('.row'); // Find the closest parent row
        row.find('.pooja_name').val(poojaName);
        row.find('.code').val(pooja_code);
        row.find('.qty').val(1).prop('readonly', false);
        row.find('.price').val(pooja_amount).prop('readonly', false);
        row.find('.total').val(pooja_amount)
        row.find('.pooja_id').val(poojaId);
       
        $('.dropdown-menu-pooja').hide(); // Hide dropdown menu
    });


    // Close dropdown on outside click
    $(document).on('click', function(e) {
        if (!$(e.target).closest('.dropdown').length) {
            $('.dropdown-menu').hide();
        }
    });


    // Duplicate to New Row
    $('.duplicate-row').click(function() {
        // Clone the first row
        const firstRow = $('#rowContainer .row:first');
        const newRow = firstRow.clone();
        // Clear input values in the new row (optional)
        newRow.find('input').val('');
        newRow.find('.duplicate-row').remove();
        newRow.find('.remove-btn-div').remove();
        // Add a remove button to the new row
        const removeBtn = $('<button type="button" class="btn btn-danger remove-row rmr">Remove</button>');
        const removeCol = $('<div class="col-sm-1"></div>').append(removeBtn);
        newRow.append(removeCol);
        // Append the new row to the container
        $('#rowContainer').append(newRow);
    });


    // Remove entire row
    $(document).on('click', '.remove-row', function() {
        // Remove the closest .row element
        $(this).closest('.row').remove();
      });


    $(document).on('keyup', '.code', function(e) {
        var keyCode = e.keyCode || e.which;
      //  if (keyCode == 9) {
         // e.preventDefault();
         console.log(frames);
         pooja_code = $(this).val();  // store values on based onn code
         var row = $(this).closest('.row'); // Find the closest parent row
          if(pooja_code)
          {
            $.ajax({
                url:search_on_code,
                data:{
                        search_value:pooja_code
                      },  
                dataType: 'json',
                type:'GET',
                success: function(response) {    
                    if(response.data.length > 0)
                    {
                        pooja_amount =  response.data[0].amount;
                        pooja_name = response.data[0].pooja_name;
                        console.log(response.data)
                        row.find('.pooja_name').val(pooja_name);
                        row.find('.qty').val(1).prop('readonly', false);
                        row.find('.price').val(pooja_amount).prop('readonly', false);
                        row.find('.total').val(pooja_amount);
                        row.find('.pooja_id').val(response.data[0].id);
                    }
                    else
                    {
                        row.find('.pooja_name').val('');
                        row.find('.qty').val('').prop('readonly', true);
                        row.find('.price').val('').prop('readonly', true);
                        row.find('.total').val('');
                    }
                },
                error: function(xhr, status, error) {
                   // console.error(error);
                }
            });
          }
       // }
    });


    // Quantity Calculation using on change
    $(document).on('keydown', '.qty', function(e)
    {
        var keyCode = e.keyCode || e.which;
        if (keyCode == 9) {
          pooja_qty = $(this).val();
            var qty_row = $(this).closest('.row'); // Find the closest parent row
            var qty_amount = qty_row.find('.price').val();
            if(pooja_qty > 0)
            {
                qty_row.find('.total').val(pooja_qty * qty_amount);
            }
            else{
                qty_row.find('.qty').val(1);
                qty_row.find('.total').val(1 * qty_amount);
                alert("Enter Valid Amount");
            }
        }
    });


    // Price Calculation using on change
    $(document).on('keydown', '.price', function(e)
    {
        var keyCode = e.keyCode || e.which;
        if (keyCode == 9)
        {
            pooja_amount = $(this).val();
            var amount_row = $(this).closest('.row'); // Find the closest parent row
            var amount_qty = amount_row.find('.qty').val();
            if(pooja_amount >= 0)
            {
                amount_row.find('.total').val(amount_qty * pooja_amount);
            }
            else
            {
                amount_row.find('.price').val(0);
                amount_row.find('.total').val(amount_qty * 0);
                alert("Enter Valid Amount");
            }
        }
    });


    //Submit seva Pooja
    $('.submit_pooja_form').click(function(){
        var btn = $(this);
        btn.prop('disabled', true);


        var get_current_date= $('.current_date').val();
        var get_current_time = $('.current_time').val();
        var payment_method = $('.payment_type').val();
        var bill_desc = $('.bill_desc').val();


        if(customerId == '')
        {
            btn.prop('disabled', false);
            alert("Please Select Customer");
            return;
        }
       var i =0;
       poojaDetails = [];
       let over_all_total = 0;
        $('.sub_pooja').each(function()
        {
            var temp_code = $(this).find('.code').val();
            var temp_pooja_name = $(this).find('.pooja_name').val();
            var temp_qty = $(this).find('.qty').val();
            var temp_pooja_id = $(this).find('.pooja_id').val();
            if(temp_qty == '' || temp_qty == '0')
            {
                btn.prop('disabled', false);
                alert("Please select pooja or remove row");
                return;
            }
            var temp_price = $(this).find('.price').val();
            var temp_total = $(this).find('.total').val();
            over_all_total = parseInt(over_all_total) + parseInt(temp_total);
             // Add pooja details to the array
             poojaDetails.push({
                code: temp_code,
                pooja_name: temp_pooja_name,
                qty: temp_qty,
                price: temp_price,
                total: temp_total,
                pooja_id: temp_pooja_id,
            });
        });
      if(poojaDetails.length > 0)
      {
        btn.text('Submitting...');
        $.ajax({


            url:submit_pooja_values, // Replace with your actual backend endpoint
            data:{ pooja_details: poojaDetails,
                    user_id:customerId,
                    current_date:get_current_date,
                    current_time:get_current_time,
                    over_all_total : over_all_total,
                    payment_method: payment_method,
                    bill_desc: bill_desc,
             },
             type: 'POST',
             dataType: 'json',
            success: function(response) {
                // Handle success response
                console.log('Submission successful:', response);
                 $(this).text('Submit');
                if(response.code == 200)
                {
                     btn.prop('disabled', false);
                    alert(response.status);
                   location.reload();
                }
                else
                {
                    alert("Someting Went Wrong");
                }
               
                // Optionally, you can redirect or perform other actions after successful submission
            },
            error: function(xhr, status, error) {
                // Handle error response
                console.error('Error:', error);
            }
        });
      }
       
       
    });
});




const ThermalPrinter = require("node-thermal-printer").printer;
const Types = require("node-thermal-printer").types;


function printReceipt(data) {
    let printer = new ThermalPrinter({
        type: Types.EPSON,
        interface: '/dev/usb/lp0', // Change for your printer
    });


    printer.alignCenter();
    printer.println("RAGA PVT LTD");
    printer.println(data.address);
    printer.println("-------------------------------");


    printer.alignLeft();
    printer.println(`Receipt No: ${data.receipt_no}`);
    printer.println(`Date: ${data.receipt_date} ${data.receipt_time}`);
    printer.println(`Customer: ${data.customer_name}`);
    printer.println(`Payment Mode: ${data.payment_method_id}`);
    printer.println("-------------------------------");


    data.items.forEach(item => {
        printer.println(`${item.pooja_name} x${item.qty}  Rs.${item.price}`);
    });


    printer.println("-------------------------------");
    printer.alignRight();
    printer.println(`Grand Total: Rs.${data.grand_total}`);
    printer.alignCenter();
    printer.println("\nThank you for visiting!\n");
    printer.cut();


    printer.execute()
        .then(() => console.log("Print done!"))
        .catch(err => console.error("Print failed:", err));
}



